 20→/**
 21→ * Main entry point for secman CLI application
 22→ *
 23→ * Usage (future with Picocli):
 24→ *   secman query [options]
 25→ *   secman config [options]
 26→ *   secman monitor [options]
 27→ *   secman help
 28→ *
 29→ */
 30→class SecmanCli {
 31→    private val log = LoggerFactory.getLogger(SecmanCli::class.java)
 32→
 33→    private fun createCliContext(): ApplicationContext {
 34→        return ApplicationContext.builder().environments("cli").start()
 35→    }
 36→
 37→    fun execute(args: Array<String>): Int {
 38→        return when {
 39→            args.isEmpty() || args[0] == "--help" || args[0] == "-h" -> showHelp()
 40→            args[0] == "help" -> {
 41→                when {
 42→                    args.size > 2 && args[1] == "query" && args[2] == "servers" -> showCommandHelp("query-servers")
 43→                    args.size > 2 && args[1] == "manage-user-mappings" && args[2] == "s3" -> showCommandHelp("manage-user-mappings-s3")
 44→                    args.size > 1 -> showCommandHelp(args[1])
 45→                    else -> showHelp()
 46→                }
 47→            }
 48→            args[0] == "query" && args.size > 1 && args[1] == "--help" -> showCommandHelp("query")
 49→            args[0] == "query" && args.size > 1 && args[1] == "servers" && args.any { it == "--help" || it == "-h" } -> showCommandHelp("query-servers")
 50→            args[0] == "query" && args.size > 1 && args[1] == "servers" -> {
 51→                val serversCommand = ServersCommand()
 52→                // Parse remaining args into properties
 53→                var i = 2
 54→                while (i < args.size) {
 55→                    when {
 56→                        args[i] == "--hostnames" && i + 1 < args.size -> {
 57→                            serversCommand.hostnames = args[i + 1].split(",").map { it.trim() }
 58→                            i++
 59→                        }
 60→                        args[i] == "--device-type" -> {
 61→                            // Check if next arg exists and is not another flag
 62→                            if (i + 1 < args.size && !args[i + 1].startsWith("--")) {
 63→                                serversCommand.deviceType = args[i + 1]
 64→                                i++
 65→                            } else {
 66→                                // No value provided, default to SERVER
 67→                                serversCommand.deviceType = "SERVER"
 68→                                System.out.println("Info: No device type specified, defaulting to SERVER")
 69→                            }
 70→                        }
 71→                        args[i] == "--severity" && i + 1 < args.size -> {
 72→                            serversCommand.severity = args[i + 1]
 73→                            i++
 74→                        }
 75→                        args[i] == "--min-days-open" && i + 1 < args.size -> {
 76→                            serversCommand.minDaysOpen = args[i + 1].toIntOrNull() ?: 30
 77→                            i++
 78→                        }
 79→                        args[i] == "--last-seen-days" && i + 1 < args.size -> {
 80→                            serversCommand.lastSeenDays = args[i + 1].toIntOrNull() ?: 0
 81→                            i++
 82→                        }
 83→                        args[i] == "--limit" && i + 1 < args.size -> {
 84→                            serversCommand.limit = args[i + 1].toIntOrNull() ?: 800
 85→                            i++
 86→                        }
 87→                        args[i] == "--client-id" && i + 1 < args.size -> {
 88→                            serversCommand.clientId = args[i + 1]
 89→                            i++
 90→                        }
 91→                        args[i] == "--client-secret" && i + 1 < args.size -> {
 92→                            serversCommand.clientSecret = args[i + 1]
 93→                            i++
 94→                        }
 95→                        args[i] == "--save" -> serversCommand.save = true
 96→                        args[i] == "--dry-run" -> serversCommand.dryRun = true
 97→                        args[i] == "--verbose" -> serversCommand.verbose = true
 98→                    }
 99→                    i++
100→                }
101→                serversCommand.execute()
102→            }
103→            args[0] == "query" && args.any { it == "--help" || it == "-h" } -> showCommandHelp("query")
104→            args[0] == "query" -> {
105→                val queryCommand = QueryCommand()
106→                // Parse remaining args into properties
107→                var i = 1
108→                while (i < args.size) {
109→                    when {
110→                        args[i] == "--hostname" && i + 1 < args.size -> {
111→                            queryCommand.hostname = args[i + 1]
112→                            i++
113→                        }
114→                        args[i] == "--severity" && i + 1 < args.size -> {
115→                            queryCommand.severity = args[i + 1]
116→                            i++
117→                        }
118→                        args[i] == "--product" && i + 1 < args.size -> {
119→                            queryCommand.product = args[i + 1]
120→                            i++
121→                        }
122→                        args[i] == "--limit" && i + 1 < args.size -> {
123→                            queryCommand.limit = args[i + 1].toIntOrNull() ?: 100
124→                            i++
125→                        }
126→                        args[i] == "--format" && i + 1 < args.size -> {
127→                            queryCommand.format = args[i + 1]
128→                            i++
129→                        }
130→                        args[i] == "--output" && i + 1 < args.size -> {
131→                            queryCommand.outputFile = args[i + 1]
132→                            i++
133→                        }
134→                        args[i] == "--client-id" && i + 1 < args.size -> {
135→                            queryCommand.clientId = args[i + 1]
136→                            i++
137→                        }
138→                        args[i] == "--client-secret" && i + 1 < args.size -> {
139→                            queryCommand.clientSecret = args[i + 1]
140→                            i++
141→                        }
142→                        args[i] == "--save" -> queryCommand.save = true
143→                        args[i] == "--verbose" -> queryCommand.verbose = true
144→                    }
145→                    i++
146→                }
147→                queryCommand.execute()
148→            }
149→            args[0] == "config" && args.any { it == "--help" || it == "-h" } -> showCommandHelp("config")
150→            args[0] == "config" -> {
151→                val configCommand = ConfigCommand()
152→                // Parse remaining args into properties
153→                for (i in 1 until args.size) {
154→                    when {
155→                        args[i] == "--client-id" && i + 1 < args.size -> configCommand.clientId = args[i + 1]
156→                        args[i] == "--client-secret" && i + 1 < args.size -> configCommand.clientSecret = args[i + 1]
157→                        args[i] == "--base-url" && i + 1 < args.size -> configCommand.baseUrl = args[i + 1]
158→                        args[i] == "--show" -> configCommand.show = true
159→                        args[i] == "--format" && i + 1 < args.size -> configCommand.format = args[i + 1]
160→                    }
161→                }
162→                configCommand.execute()
163→            }
164→            args[0] == "monitor" && args.any { it == "--help" || it == "-h" } -> showCommandHelp("monitor")
165→            args[0] == "monitor" -> {
166→                val monitorCommand = MonitorCommand()
167→                // Parse remaining args into properties
168→                var i = 1
169→                while (i < args.size) {
170→                    when {
171→                        args[i] == "--interval" && i + 1 < args.size -> {
172→                            monitorCommand.intervalMinutes = args[i + 1].toIntOrNull() ?: 5
173→                            i++
174→                        }
175→                        args[i] == "--hostnames" && i + 1 < args.size -> {
176→                            monitorCommand.hostnames = args[i + 1].split(",").map { it.trim() }
177→                            i++
178→                        }
179→                        args[i] == "--backend-url" && i + 1 < args.size -> {
180→                            monitorCommand.backendUrl = args[i + 1]
181→                            i++
182→                        }
183→                        args[i] == "--config" && i + 1 < args.size -> {
184→                            monitorCommand.configPath = args[i + 1]
185→                            i++
186→                        }
187→                        args[i] == "--dry-run" -> monitorCommand.dryRun = true
188→                        args[i] == "--verbose" -> monitorCommand.verbose = true
189→                        args[i] == "--no-storage" -> monitorCommand.noStorage = true
190→                    }
191→                    i++
192→                }
193→                monitorCommand.execute()
194→            }
195→            args[0] == "manage-user-mappings" -> {
196→                // Use Picocli with Micronaut DI for user mapping commands
197→                // Drop the first argument (command name) before passing to PicocliRunner
198→                val subArgs = args.drop(1).toTypedArray()
199→                createCliContext().use { ctx ->
200→                    PicocliRunner.run(ManageUserMappingsCommand::class.java, ctx, *subArgs)
201→                }
202→                0
203→            }
204→            args[0] == "send-notifications" -> {
205→                // Use Picocli with Micronaut DI for notification command
206→                // Drop the first argument (command name) before passing to PicocliRunner
207→                val subArgs = args.drop(1).toTypedArray()
208→                createCliContext().use { ctx ->
209→                    PicocliRunner.run(SendNotificationsCommand::class.java, ctx, *subArgs)
210→                }
211→                0
212→            }
213→            args[0] == "manage-workgroups" -> {
214→                // Use Picocli with Micronaut DI for workgroup commands
215→                // Drop the first argument (command name) before passing to PicocliRunner
216→                val subArgs = args.drop(1).toTypedArray()
217→                createCliContext().use { ctx ->
218→                    PicocliRunner.run(ManageWorkgroupsCommand::class.java, ctx, *subArgs)
219→                }
220→                0
221→            }
222→            args[0] == "add-vulnerability" -> {
223→                // Use Picocli with Micronaut DI for add-vulnerability command
224→                // Feature: 052-cli-add-vulnerability
225→                val subArgs = args.drop(1).toTypedArray()
226→                createCliContext().use { ctx ->
227→                    PicocliRunner.run(AddVulnerabilityCommand::class.java, ctx, *subArgs)
228→                }
229→                0
230→            }
231→            args[0] == "export-requirements" -> {
232→                // Use Picocli with Micronaut DI for export-requirements command
233→                // Feature: 057-cli-mcp-requirements
234→                val subArgs = args.drop(1).toTypedArray()
235→                createCliContext().use { ctx ->
236→                    PicocliRunner.run(ExportRequirementsCommand::class.java, ctx, *subArgs)
237→                }
238→                0
239→            }
240→            args[0] == "add-requirement" -> {
241→                // Use Picocli with Micronaut DI for add-requirement command
242→                // Feature: 057-cli-mcp-requirements
243→                val subArgs = args.drop(1).toTypedArray()
244→                createCliContext().use { ctx ->
245→                    PicocliRunner.run(AddRequirementCommand::class.java, ctx, *subArgs)
246→                }
247→                0
248→            }
249→            args[0] == "delete-all-requirements" -> {
250→                // Use Picocli with Micronaut DI for delete-all-requirements command
251→                // Feature: 057-cli-mcp-requirements
252→                val subArgs = args.drop(1).toTypedArray()
253→                createCliContext().use { ctx ->
254→                    PicocliRunner.run(DeleteAllRequirementsCommand::class.java, ctx, *subArgs)
255→                }
256→                0
257→            }
258→            args[0] == "send-admin-summary" -> {
259→                // Use Picocli with Micronaut DI for send-admin-summary command
260→                // Feature: 070-admin-summary-email
261→                val subArgs = args.drop(1).toTypedArray()
262→                createCliContext().use { ctx ->
263→                    PicocliRunner.run(SendAdminSummaryCommand::class.java, ctx, *subArgs)
264→                }
265→                0
266→            }
267→            args[0] == "deduplicate-vulnerabilities" -> {
268→                // Remove duplicate vulnerability records from the database
269→                val subArgs = args.drop(1).toTypedArray()
270→                createCliContext().use { ctx ->
271→                    PicocliRunner.run(DeduplicateVulnerabilitiesCommand::class.java, ctx, *subArgs)
272→                }
273→                0
274→            }
275→            else -> {
276→                System.err.println("ERROR: Unknown command: '${args[0]}'")
277→
278→                // Suggest parent command for known subcommands used at the wrong level
279→                val subcommandHints = mapOf(
280→                    "list-bucket" to "manage-user-mappings",
281→                    "import-s3" to "manage-user-mappings",
282→                    "add-domain" to "manage-user-mappings",
283→                    "add-aws" to "manage-user-mappings",
284→                    "assign-assets" to "manage-workgroups",
285→                    "remove-assets" to "manage-workgroups",
286→                    "servers" to "query"
287→                )
288→                val parentCommand = subcommandHints[args[0]]
289→                if (parentCommand != null) {
290→                    System.err.println()
291→                    System.err.println("Did you mean: secman $parentCommand ${args.joinToString(" ")}")
292→                    System.err.println()
293→                }
294→
295→                showHelp()
296→                1
297→            }
298→        }
