 1→package com.secman.config
 2→
 3→import com.secman.domain.UseCase
 4→import com.secman.repository.UseCaseRepository
 5→import io.micronaut.context.event.ApplicationEventListener
 6→import io.micronaut.runtime.event.ApplicationStartupEvent
 7→import io.micronaut.context.annotation.Requires
 8→import io.micronaut.transaction.annotation.Transactional
 9→import jakarta.inject.Singleton
10→import org.slf4j.LoggerFactory
11→
12→@Requires(notEnv = ["cli"])
13→@Singleton
14→open class SystemUseCaseInitializer(
15→    private val useCaseRepository: UseCaseRepository
16→) : ApplicationEventListener<ApplicationStartupEvent> {
17→
18→    private val log = LoggerFactory.getLogger(SystemUseCaseInitializer::class.java)
19→
20→    companion object {
21→        val SYSTEM_USE_CASE_NAMES = listOf("IT", "OT", "NT")
22→    }
23→
24→    override fun onApplicationEvent(event: ApplicationStartupEvent) {
25→        initializeSystemUseCases()
26→    }
27→
28→    @Transactional
29→    open fun initializeSystemUseCases() {
30→        for (name in SYSTEM_USE_CASE_NAMES) {
31→            try {
32→                val existing = useCaseRepository.findByNameIgnoreCase(name)
33→                if (existing.isPresent) {
34→                    val useCase = existing.get()
35→                    if (!useCase.systemProtected) {
36→                        useCase.systemProtected = true
37→                        useCaseRepository.update(useCase)
38→                        log.info("Marked existing use case '{}' as system-protected", name)
39→                    }
40→                } else {
41→                    val useCase = UseCase(name = name, systemProtected = true)
42→                    useCaseRepository.save(useCase)
43→                    log.info("Created system use case '{}'", name)
44→                }
45→            } catch (e: Exception) {
46→                log.error("Failed to initialize system use case '{}': {}", name, e.message, e)
47→            }
48→        }
49→    }
50→}
